/**
 * @summary Search broadcasts by tag or keyword
 */
export const getSearchBroadcastsUrl = (params: SearchBroadcastsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/broadcasts/search?${stringifiedParams}`
    : `/api/broadcasts/search`;
};

export const searchBroadcasts = async (
  params: SearchBroadcastsParams,
  options?: RequestInit,
): Promise<Broadcast[]> => {
  return customFetch<Broadcast[]>(getSearchBroadcastsUrl(params), {
    ...options,
    method: "GET",
  });
};

